// // This module operates on the positive edge of the clock signal (CLK_P) and includes an active-high reset (RESET_A). It takes a single data input (D) and two control signals (ctrl_x, ctrl_y) to determine its output (Q). Depending on the combination of control signals, the output can be set to either a logic HIGH, the negation of D, the value of D, or a logic LOW. This design effectively functions as a controlled latch or flip-flop, allowing for different operations based on the control inputs while ensuring reset functionality.
module top_module(
    RESET_B,
    CLK_N  ,
    D      ,
    Q      ,
    ctrl_a ,
    ctrl_b
);input  RESET_B;
    input  CLK_N  ;
    input  D      ;
    output Q      ;
    input  ctrl_a ;
    input  ctrl_b ;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    reg Q_reg;
    always @(negedge CLK_N or negedge RESET_B) begin
        if (!RESET_B) begin
            Q_reg <= 1'b0;
        end else begin
            case ({ctrl_a, ctrl_b})
                2'b00: Q_reg <= 1'b0;
                2'b01: Q_reg <= ~D;
                2'b10: Q_reg <= D;
                2'b11: Q_reg <= 1'b1;
            endcase
        end
    end

    assign Q = Q_reg;

endmodule
